        bars1 = ax1.bar([i - width/2 for i in x], top_10['Raw_Acc'], width, label='Intensywność Akumulacji (%)', color=t['bull'], alpha=0.8)
        
        # Zmiana ceny - czerwień oznacza, że cena złośliwie spada, mimo że fundusze kupują!
