        ax1.set_ylabel('Siła Kompresji (Max 100)', color=t['spring'])
        ax2.set_ylabel('Szerokość Wstęg (%)', color=t['accent'])
        
        # Oś kompresji ma twardy sufit na 110, by było widać jak blisko 100 jesteśmy
